mapper.select:
SELECT wo.WO_ID AS woId, wo.PLANT_CD AS plantCd, p.PLANT_NM AS plantNm, wo.WO_NO AS woNo, wo.PLAN_ID AS planId, wo.WO_DT AS woDt, wo.ITEM_CD AS itemCd, i.ITEM_NM AS itemNm, wo.WO_QTY AS woQty, wo.WORKCENTER_CD AS workcenterCd, wo.EQUIPMENT_CD AS equipmentCd, wo.WORKER_ID AS workerId, wo.PLAN_START_DTM AS planStartDtm, wo.PLAN_END_DTM AS planEndDtm, wo.ACTUAL_START_DTM AS actualStartDtm, wo.ACTUAL_END_DTM AS actualEndDtm, wo.GOOD_QTY AS goodQty, wo.DEFECT_QTY AS defectQty, wo.WO_STATUS AS woStatus, wo.PRIORITY AS priority, wo.LOT_NO AS lotNo, wo.PARENT_WO_ID AS parentWoId, wo.ORDER_NO AS orderNo, wo.DELIVERY_DT AS deliveryDt, wo.WO_RMK AS woRmk FROM PLN_WORK_ORDER wo JOIN MST_PLANT p ON p.PLANT_CD = wo.PLANT_CD LEFT JOIN MST_ITEM i ON i.ITEM_CD = wo.ITEM_CD WHERE 1 = 1
AND wo.PLANT_CD = #{plantCd}
AND wo.ITEM_CD = #{itemCd}
AND wo.WO_STATUS = #{woStatus}
AND wo.WO_DT >= #{woFromDt}
AND wo.WO_DT <= #{woToDt}
ORDER BY wo.WO_DT DESC, wo.PRIORITY ASC, wo.WO_ID DESC

mapper.update:
UPDATE PLN_WORK_ORDER
SET WO_STATUS = #{woStatus},
    ACTUAL_START_DTM = COALESCE(ACTUAL_START_DTM, #{actualStartDtm}),
    ACTUAL_END_DTM = #{actualEndDtm},
    UPD_USER_ID = #{updUserId}
WHERE WO_ID = #{woId}

UPDATE PLN_WORK_ORDER
SET GOOD_QTY = COALESCE(GOOD_QTY, 0) + #{goodQty},
    DEFECT_QTY = COALESCE(DEFECT_QTY, 0) + #{defectQty},
    UPD_USER_ID = #{updUserId}
WHERE WO_ID = #{woId}

mapper.select:
SELECT wo.WO_ID AS woId, wo.PLANT_CD AS plantCd, p.PLANT_NM AS plantNm, wo.WO_NO AS woNo, wo.PLAN_ID AS planId, wo.WO_DT AS woDt, wo.ITEM_CD AS itemCd, i.ITEM_NM AS itemNm, wo.WO_QTY AS woQty, wo.WORKCENTER_CD AS workcenterCd, wo.EQUIPMENT_CD AS equipmentCd, wo.WORKER_ID AS workerId, wo.PLAN_START_DTM AS planStartDtm, wo.PLAN_END_DTM AS planEndDtm, wo.ACTUAL_START_DTM AS actualStartDtm, wo.ACTUAL_END_DTM AS actualEndDtm, wo.GOOD_QTY AS goodQty, wo.DEFECT_QTY AS defectQty, wo.WO_STATUS AS woStatus, wo.PRIORITY AS priority, wo.LOT_NO AS lotNo, wo.PARENT_WO_ID AS parentWoId, wo.ORDER_NO AS orderNo, wo.DELIVERY_DT AS deliveryDt, wo.WO_RMK AS woRmk FROM PLN_WORK_ORDER wo JOIN MST_PLANT p ON p.PLANT_CD = wo.PLANT_CD LEFT JOIN MST_ITEM i ON i.ITEM_CD = wo.ITEM_CD WHERE 1 = 1
AND wo.PLANT_CD = #{plantCd}
AND wo.ITEM_CD = #{itemCd}
AND wo.WO_STATUS = #{woStatus}
AND wo.WO_DT >= #{woFromDt}
AND wo.WO_DT <= #{woToDt}
ORDER BY wo.WO_DT DESC, wo.PRIORITY ASC, wo.WO_ID DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM PLN_WORK_ORDER wo
WHERE 1 = 1

    AND wo.PLANT_CD = #{plantCd}


    AND wo.ITEM_CD = #{itemCd}


    AND wo.WO_STATUS = #{woStatus}


    AND wo.WO_DT >= #{woFromDt}


    AND wo.WO_DT <= #{woToDt}

SELECT COUNT(*)
FROM PLN_WORK_ORDER
WHERE WO_DT = #{woDt}
